#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        for (int i = 1; i <= 5; ++i) {
            printf("%d - %d\n", i, i * i);
        }
    }
    return 0;
}

